{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = [
            new Recipe { Id = 1, Title = "Margherita Pizza", Description = "Classic Neapolitan pizza with fresh mozzarella, basil, and tomato sauce.", PrepTimeMinutes = 30 },
            new Recipe { Id = 2, Title = "Pasta Carbonara", Description = "Creamy Roman pasta with pancetta, egg yolk, and Pecorino Romano.", PrepTimeMinutes = 25 },
            new Recipe { Id = 3, Title = "Tiramisu", Description = "Layered coffee-soaked ladyfingers with mascarpone cream.", PrepTimeMinutes = 45 },
        ],
        [2] = [
            new Recipe { Id = 4, Title = "Chicken Tikka Masala", Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.", PrepTimeMinutes = 50 },
            new Recipe { Id = 5, Title = "Palak Paneer", Description = "Fresh paneer cubes in a smooth, seasoned spinach gravy.", PrepTimeMinutes = 40 },
            new Recipe { Id = 6, Title = "Biryani", Description = "Fragrant basmati rice layered with spiced meat and caramelized onions.", PrepTimeMinutes = 90 },
        ],
        [3] = [
