            new Recipe { Id = 8, Title = "Guacamole", Description = "Creamy avocado dip with lime, cilantro, and jalapeño.", PrepTimeMinutes = 10 },
            new Recipe { Id = 9, Title = "Churros", Description = "Crispy fried dough sticks dusted with cinnamon sugar.", PrepTimeMinutes = 35 },
