@page "/recipes/{CuisineId:int}"
@using sv_7ea0d99129d14ff2ac0680f506879c9b.Models
@using sv_7ea0d99129d14ff2ac0680f506879c9b.Services
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@_error</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2" role="status">Refreshing…</div>
    }

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Title</th>
                    <th>Description</th>
                    <th>Prep Time (min)</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var recipe in GetSortedRecipes())
                {
                    <tr>
                        <td>@recipe.Title</td>
                        <td>@recipe.Description</td>
                        <td>@recipe.PrepTimeMinutes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;

    private int _lastLoadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposalCts = new();

    public override async Task OnParametersSetAsync()
    {
        if (CuisineId == _lastLoadedCuisineId)
        {
            // Sort changed but cuisine didn't — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for a previous cuisine.
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposalCts.Token);
        var cts = _loadCts;

        _error = null;
        _isRefreshing = _recipes is not null;
        _lastLoadedCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
            {
                return;
            }

            _recipes = results;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // A newer load superseded this one, or the component is being disposed.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
        {
            return [];
        }

        return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    private async Task RetryAsync()
    {
        _error = null;
        _lastLoadedCuisineId = 0; // Force reload
        await LoadRecipesAsync();
    }

    public async ValueTask DisposeAsync()
    {
        await _disposalCts.CancelAsync();
        _disposalCts.Dispose();

        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }
    }
}

